import json, csv, os
from datetime import datetime, date
import pandas as pd

FIELD_MAP = {
    'user_id':'user_id','id':'user_id','userId':'user_id',
    'email':'email','email_address':'email',
    'full_name':'name','name':'name','userName':'name',
    'registration_date':'created_date','created_at':'created_date','joined':'created_date',
    'status':'status','is_active':'status','active':'status',
}

def norm_date(v):
    if v is None: return None
    if isinstance(v,(datetime,date)): return v.strftime('%Y-%m-%d')
    s=str(v).strip()
    if not s: return None
    for fmt in ('%Y-%m-%d','%Y/%m/%d','%m/%d/%Y','%d-%m-%Y','%Y-%m-%dT%H:%M:%S','%m-%d-%Y'):
        try: return datetime.strptime(s.split('T')[0] if 'T' in s and fmt=='%Y-%m-%d' else s, fmt).strftime('%Y-%m-%d')
        except ValueError: continue
    try: return pd.to_datetime(s).strftime('%Y-%m-%d')
    except Exception: return s

def norm_status(v):
    if v is None: return None
    if isinstance(v,bool): return 'active' if v else 'inactive'
    s=str(v).strip()
    if s.lower() in ('true','1'): return 'active'
    if s.lower() in ('false','0'): return 'inactive'
    return s

def to_rec(raw):
    r={}
    for k,v in raw.items():
        if k not in FIELD_MAP: continue
        uk=FIELD_MAP[k]
        if v is None: continue
        if isinstance(v,float) and pd.isna(v): continue
        if uk=='user_id': v=int(v)
        elif uk=='created_date': v=norm_date(v)
        elif uk=='status': v=norm_status(v)
        else: v=str(v).strip()
        r[uk]=v
    return r

# read A
A=[to_rec(u) for u in json.load(open('/data/source_a/users.json'))]
# read B
B=[to_rec(r) for r in csv.DictReader(open('/data/source_b/users.csv'))]
# read C
dfc=pd.read_parquet('/data/source_c/users.parquet')
C=[to_rec({k:(None if (not isinstance(v,bool) and pd.isna(v)) else v) for k,v in row.items()}) for row in dfc.to_dict('records')]

sources={'source_a':A,'source_b':B,'source_c':C}
order=['source_a','source_b','source_c']

# index by user_id
by_id={}
for sname in order:
    for rec in sources[sname]:
        uid=rec.get('user_id')
        if uid is None: continue
        by_id.setdefault(uid,{})[sname]=rec

FIELDS=['name','email','created_date','status']
merged=[]
conflicts=[]
for uid in sorted(by_id):
    present=by_id[uid]
    out={'user_id':uid}
    for f in FIELDS:
        vals={s:present[s][f] for s in order if s in present and f in present[s]}
        selected=None
        for s in order:
            if s in vals: selected=vals[s]; break
        if selected is not None: out[f]=selected
        if len(set(vals.values()))>1:
            conflicts.append({'user_id':uid,'field':f,'values':vals,'selected':selected})
    merged.append(out)

df=pd.DataFrame(merged)
for c in ['name','email','created_date','status']:
    if c not in df.columns: df[c]=None
df['user_id']=df['user_id'].astype('int64')
for c in ['name','email','created_date','status']:
    df[c]=df[c].astype('object')
df=df[['user_id','name','email','created_date','status']]
df.to_parquet('/app/merged_users.parquet',index=False)

report={'total_conflicts':len(conflicts),'conflicts':conflicts}
json.dump(report,open('/app/conflicts.json','w'),indent=2)
print(df.to_string())
print(json.dumps(report,indent=2))
PY
python3 /app/merge.py

